          (Option.map x.customEntityTypesNotFound
             ~f:CustomEntityTypeNames.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let customEntityTypesNotFound =
        (Option.map ~f:CustomEntityTypeNames.of_xml)
          (Xml.child xml_arg0 "CustomEntityTypesNotFound") in
      let customEntityTypes =
        (Option.map ~f:CustomEntityTypes.of_xml)
          (Xml.child xml_arg0 "CustomEntityTypes") in
      make ?customEntityTypesNotFound ?customEntityTypes ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let customEntityTypesNotFound =
        field_map json__ "CustomEntityTypesNotFound"
          CustomEntityTypeNames.of_json in
      let customEntityTypes =
        field_map json__ "CustomEntityTypes" CustomEntityTypes.of_json in
      make ?customEntityTypesNotFound ?customEntityTypes ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
