module DeltaTargetCompressionType =
  struct
    type nonrec t =
      | Uncompressed 
      | Snappy 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | Uncompressed -> "uncompressed"
      | Snappy -> "snappy"
      | Non_static_id s -> s
    let of_string =
      function
