        EnclosedInStringProperty.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "Table") in
      let database =
        EnclosedInStringProperty.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "Database") in
      let name =
        NodeName.of_xml (Xml.child_exn ~context:context_ xml_arg0 "Name") in
      make ?outputSchemas ?additionalDeltaOptions ~table ~database ~name ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let outputSchemas =
        field_map json__ "OutputSchemas" GlueSchemas.of_json in
      let additionalDeltaOptions =
        field_map json__ "AdditionalDeltaOptions" AdditionalOptions.of_json in
      let table =
        field_map_exn json__ "Table" EnclosedInStringProperty.of_json in
      let database =
        field_map_exn json__ "Database" EnclosedInStringProperty.of_json in
      let name = field_map_exn json__ "Name" NodeName.of_json in
      make ?outputSchemas ?additionalDeltaOptions ~table ~database ~name ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Specifies a Delta Lake data source that is registered in the Glue Data Catalog."]
